export interface TranscriptionResult {
  text: string;
  language?: string;
  summary?: string;
  timestamp: number;
}

export interface FileState {
  file: File | null;
  processing: boolean;
  error: string | null;
  result: TranscriptionResult | null;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { TranscriptionResult } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export const transcribeMedia = async (
  base64Data: string,
  mimeType: string
): Promise<TranscriptionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Please transcribe the following media file accurately.
    1. Provide a full, verbatim transcription of the spoken content.
    2. Identify the language used.
    3. Provide a brief 3-sentence summary of the main topics discussed.

    Format the response clearly with sections for 'Transcription', 'Language', and 'Summary'.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          { text: prompt },
        ],
      },
    });

    const output = response.text || "No transcription generated.";

    return {
      text: output,
      timestamp: Date.now(),
    };
  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    throw new Error("Failed to transcribe media. Please ensure the file is not too large and is a valid audio/video format.");
  }
};

