export interface TranscriptionResult {
  text: string;
  language?: string;
  summary?: string;
  timestamp: number;
}

export interface FileState {
  file: File | null;
  processing: boolean;
  uploadProgress?: number;
  stage?: 'uploading' | 'processing' | 'complete';
  error: string | null;
  result: TranscriptionResult | null;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { TranscriptionResult } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';
const API_KEY = process.env.API_KEY || '';

// 20MB limit for inline processing. Files larger than this use the Files API.
const INLINE_SIZE_LIMIT = 20 * 1024 * 1024; 

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = error => reject(error);
  });
};

// Helper to upload large files to Gemini Files API
const uploadLargeFile = async (file: File, onProgress: (percent: number) => void): Promise<string> => {
  const metaData = { file: { display_name: file.name } };

  // 1. Initiate Resumable Upload
  const startUpload = await fetch(`https://generativelanguage.googleapis.com/upload/v1beta/files?key=${API_KEY}`, {
    method: 'POST',
    headers: {
      'X-Goog-Upload-Protocol': 'resumable',
      'X-Goog-Upload-Command': 'start',
      'X-Goog-Upload-Header-Content-Length': file.size.toString(),
      'X-Goog-Upload-Header-Content-Type': file.type,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(metaData),
  });

  const uploadUrl = startUpload.headers.get('x-goog-upload-url');
  if (!uploadUrl) throw new Error("Failed to initiate upload.");

  // 2. Upload the file content
  // Note: For a 5GB file, robust implementation would chunk this. 
  // Browser fetch can handle reasonably large blobs, but strict 5GB might require chunking logic.
  // We use the simpler single-request resumable command for this implementation.
  onProgress(10);

  const uploadResult = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'Content-Length': file.size.toString(),
      'X-Goog-Upload-Offset': '0',
      'X-Goog-Upload-Command': 'upload, finalize',
    },
    body: file,
  });

  onProgress(80);
  const fileInfo = await uploadResult.json();
  const fileUri = fileInfo.file.uri;

  // 3. Wait for file to be ACTIVE
  let state = fileInfo.file.state;
  while (state === 'PROCESSING') {
    await new Promise(r => setTimeout(r, 2000));
    const check = await fetch(`https://generativelanguage.googleapis.com/v1beta/${fileInfo.file.name}?key=${API_KEY}`);
    const checkJson = await check.json();
    state = checkJson.state;
  }

  if (state !== 'ACTIVE') {
    throw new Error("File processing failed on server side.");
  }

  onProgress(100);
  return fileUri;
};

export const transcribeMedia = async (
  file: File,
  onProgress?: (percent: number) => void
): Promise<TranscriptionResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    Analyze this media file (Python 3.14 Logic Mode).
    1. Provide a verbatim transcription.
    2. Detect the language.
    3. Summarize the key points in 3 sentences.
    Return formatted as: **Transcription**, **Language**, **Summary**.
  `;

  let contentPart: any;

  try {
    if (file.size < INLINE_SIZE_LIMIT) {
      // Small file: Use fast inline base64
      if (onProgress) onProgress(50);
      const base64 = await fileToBase64(file);
      contentPart = {
        inlineData: {
          mimeType: file.type,
          data: base64,
        },
      };
      if (onProgress) onProgress(100);
    } else {
      // Large file: Use Files API
      const fileUri = await uploadLargeFile(file, onProgress || (() => {}));
      contentPart = {
        fileData: {
          mimeType: file.type,
          fileUri: fileUri,
        },
      };
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [contentPart, { text: prompt }],
      },
    });

    const output = response.text || "No transcription generated.";

    return {
      text: output,
      timestamp: Date.now(),
    };

  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    throw new Error("Failed to process media. For very large files (5GB), ensure your connection is stable.");
  }
};

