        // Only clear if we are using a stored key, to avoid loops if env var is bad
        if (storedKey) {
            handleClearKey();
        }
        setApiKeyReady(false);
      }

      setState(prev => ({ 
        ...prev, 
        processing: false, 
        error: errorMessage
