export interface TranscriptionResult {
  transcription: string;
  language: string;
  summary: string;
  timestamp: number;
}

export interface FileState {
  file: File | null;
  processing: boolean;
  uploadProgress?: number;
  stage?: 'uploading' | 'processing' | 'complete';
  error: string | null;
  result: TranscriptionResult | null;
}

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { TranscriptionResult } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

// 20MB limit for inline processing. Files larger than this use the Files API.
const INLINE_SIZE_LIMIT = 20 * 1024 * 1024; 

const getApiKey = (providedKey?: string): string => {
  // 1. Try the key passed directly from UI
  if (providedKey && providedKey.trim() !== '') {
    return providedKey.trim();
  }

  // 2. Try environment variable (Build time or injected)
  let key = process.env.API_KEY;
  if (key && key.trim() !== '') {
    key = key.trim();
    if ((key.startsWith('"') && key.endsWith('"')) || (key.startsWith("'") && key.endsWith("'"))) {
      key = key.slice(1, -1);
    }
    return key;
  }

  throw new Error("API Key is missing. Please enter your Gemini API Key in the settings.");
};

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = error => reject(error);
  });
};

// Helper to upload large files to Gemini Files API
const uploadLargeFile = async (file: File, onProgress: (percent: number) => void, userApiKey?: string): Promise<string> => {
  const apiKey = getApiKey(userApiKey);

  const mimeType = file.type || 'application/octet-stream';
  const metaData = { file: { display_name: file.name } };

  // 1. Initiate Resumable Upload
  const startUpload = await fetch(`https://generativelanguage.googleapis.com/upload/v1beta/files`, {
    method: 'POST',
    headers: {
      'x-goog-api-key': apiKey,
      'X-Goog-Upload-Protocol': 'resumable',
      'X-Goog-Upload-Command': 'start',
      'X-Goog-Upload-Header-Content-Length': file.size.toString(),
      'X-Goog-Upload-Header-Content-Type': mimeType,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(metaData),
  });

  if (!startUpload.ok) {
    let errorMessage = `Status ${startUpload.status}`;
    try {
      const errorJson = await startUpload.json();
      if (errorJson.error && errorJson.error.message) {
        errorMessage = errorJson.error.message;
      }
    } catch {
      errorMessage = await startUpload.text();
    }
    throw new Error(`Upload initiation failed: ${errorMessage}`);
  }

  const uploadUrl = startUpload.headers.get('x-goog-upload-url');
  if (!uploadUrl) {
    throw new Error("Upload failed: Server did not return a valid upload URL.");
  }

  // 2. Upload the file content
  onProgress(10);

  const uploadResult = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'x-goog-api-key': apiKey,
      'Content-Length': file.size.toString(),
      'X-Goog-Upload-Offset': '0',
      'X-Goog-Upload-Command': 'upload, finalize',
    },
    body: file,
  });

  if (!uploadResult.ok) {
     let errorMessage = `Status ${uploadResult.status}`;
    try {
      const errorJson = await uploadResult.json();
      if (errorJson.error && errorJson.error.message) {
        errorMessage = errorJson.error.message;
      }
    } catch {
      errorMessage = await uploadResult.text();
    }
    throw new Error(`File transmission failed: ${errorMessage}`);
  }

  onProgress(80);
  const fileInfo = await uploadResult.json();
  const fileUri = fileInfo.file.uri;

  // 3. Wait for file to be ACTIVE
  let state = fileInfo.file.state;
  while (state === 'PROCESSING') {
    await new Promise(r => setTimeout(r, 2000));
    const check = await fetch(`https://generativelanguage.googleapis.com/v1beta/${fileInfo.file.name}`, {
      headers: {
        'x-goog-api-key': apiKey
      }
    });

    if (!check.ok) {
       throw new Error(`Status check failed: ${check.status}`);
    }

    const checkJson = await check.json();
    state = checkJson.state;

    if (state === 'FAILED') {
      throw new Error("File processing failed on Gemini server.");
    }
  }

  if (state !== 'ACTIVE') {
    throw new Error(`File not active. Current state: ${state}`);
  }

  onProgress(100);
  return fileUri;
};

export const transcribeMedia = async (
  file: File,
  onProgress: ((percent: number) => void) | undefined,
  userApiKey?: string
): Promise<TranscriptionResult> => {
  const apiKey = getApiKey(userApiKey);
  const ai = new GoogleGenAI({ apiKey });

  const mimeType = file.type || 'application/octet-stream';

  const prompt = "Transcribe this media file. Identify the primary language, provide a concise summary, and the full verbatim transcription.";

  let contentPart: any;

  try {
    if (file.size < INLINE_SIZE_LIMIT) {
      // Small file: Use fast inline base64
      if (onProgress) onProgress(50);
      const base64 = await fileToBase64(file);
      contentPart = {
        inlineData: {
          mimeType: mimeType,
          data: base64,
        },
      };
      if (onProgress) onProgress(100);
    } else {
      // Large file: Use Files API
      const fileUri = await uploadLargeFile(file, onProgress || (() => {}), apiKey);
      contentPart = {
        fileData: {
          mimeType: mimeType,
          fileUri: fileUri,
        },
      };
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [contentPart, { text: prompt }],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            language: {
              type: Type.STRING,
              description: "The primary language spoken in the media (e.g., 'English', 'Vietnamese')."
            },
            summary: {
              type: Type.STRING,
              description: "A concise 3-sentence summary of the content."
            },
            transcription: {
              type: Type.STRING,
              description: "The full, verbatim transcription of the media."
            }
          },
          required: ["language", "summary", "transcription"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No response from model");

    const parsed = JSON.parse(jsonText);

    return {
      transcription: parsed.transcription || "No transcription available.",
      language: parsed.language || "Unknown",
      summary: parsed.summary || "No summary available.",
      timestamp: Date.now(),
    };

  } catch (error: any) {
    console.error("Gemini Transcription Error:", error);
    throw new Error(error.message || "Failed to process media. Please check your connection and API Key.");
  }
};

import React, { useState, useEffect } from 'react';
import { FileState } from './types';
import { transcribeMedia } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<FileState>({
    file: null,
    processing: false,
    error: null,
    result: null,
    uploadProgress: 0,
    stage: 'complete'
  });

  const [activeTab, setActiveTab] = useState<'transcription' | 'summary'>('transcription');

  // API Key State Management
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);
  const [checkingKey, setCheckingKey] = useState<boolean>(true);
  const [manualKey, setManualKey] = useState<string>('');
  const [storedKey, setStoredKey] = useState<string>('');

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    setCheckingKey(true);
    try {
      const localKey = localStorage.getItem('gemini_api_key');
      if (localKey) {
        setStoredKey(localKey);
        setApiKeyReady(true);
        setCheckingKey(false);
        return;
      }
      if (process.env.API_KEY) {
        setApiKeyReady(true);
        setCheckingKey(false);
        return;
      }
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (hasKey) {
          setApiKeyReady(true);
        }
      }
    } catch (e) {
      console.error("Failed to check API key status", e);
    } finally {
      setCheckingKey(false);
    }
  };

  const handleSaveKey = () => {
    if (manualKey.trim().length > 10) {
      localStorage.setItem('gemini_api_key', manualKey.trim());
      setStoredKey(manualKey.trim());
      setApiKeyReady(true);
      setState(prev => ({ ...prev, error: null }));
    } else {
      setState(prev => ({ ...prev, error: "API Key looks too short." }));
    }
  };

  const handleClearKey = () => {
    localStorage.removeItem('gemini_api_key');
    setStoredKey('');
    setApiKeyReady(false);
    setState(prev => ({ ...prev, result: null, file: null }));
  };

  const handleConnectKey = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setApiKeyReady(true);
        setState(prev => ({ ...prev, error: null }));
      } catch (e) {
        console.error("Key selection failed", e);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const MAX_SIZE = 5 * 1024 * 1024 * 1024; // 5GB

      if (file.size > MAX_SIZE) {
         setState(prev => ({ ...prev, error: "File exceeds the 5GB limit." }));
         return;
      }

      if (!file.type.startsWith('audio/') && !file.type.startsWith('video/')) {
        setState(prev => ({ ...prev, error: "Please select an MP3 or MP4 file." }));
        return;
      }

      setState({
        file,
        processing: false,
        error: null,
        result: null,
        uploadProgress: 0,
        stage: 'complete'
      });
      setActiveTab('transcription');
    }
  };

  const startTranscription = async () => {
    if (!state.file) return;

    setState(prev => ({ 
      ...prev, 
      processing: true, 
      error: null,
      stage: 'uploading',
      uploadProgress: 0
    }));

    try {
      const result = await transcribeMedia(state.file, (progress) => {
        setState(prev => ({ 
          ...prev, 
          uploadProgress: progress,
          stage: progress < 100 ? 'uploading' : 'processing'
        }));
      }, storedKey);

      setState(prev => ({ ...prev, processing: false, result, stage: 'complete' }));
    } catch (err: any) {
      const errorMessage = err.message || "An unexpected error occurred.";
      if (errorMessage.includes("API key") || errorMessage.includes("400") || errorMessage.includes("403")) {
        if (storedKey) handleClearKey();
        setApiKeyReady(false);
      }
      setState(prev => ({ 
        ...prev, 
        processing: false, 
        error: errorMessage
      }));
    }
  };

  const downloadText = () => {
    if (!state.result) return;
    const content = `LANGUAGE: ${state.result.language}\n\nSUMMARY:\n${state.result.summary}\n\nTRANSCRIPTION:\n${state.result.transcription}`;
    const element = document.createElement("a");
    const file = new Blob([content], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `transcription_${Date.now()}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  if (checkingKey) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="animate-pulse flex flex-col items-center">
          <div className="h-4 w-4 bg-blue-500 rounded-full mb-2"></div>
          <div className="text-slate-400 text-sm">Loading App...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center py-8 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-3xl w-full text-center mb-8">
        <div className="inline-block p-1 px-3 rounded-full bg-blue-100 text-blue-700 text-xs font-bold mb-3 tracking-wide uppercase">
          Cross-Platform • 5GB Limit
        </div>
        <h1 className="text-3xl sm:text-4xl font-extrabold text-slate-900 tracking-tight mb-2">
          Gemini Converter
        </h1>
        <p className="text-slate-600">
          Convert MP3/MP4 to Text & Summary on any device.
        </p>
      </div>

      <main className="max-w-3xl w-full space-y-6">

        {!apiKeyReady && (
           <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-8 border border-slate-200 text-center animate-in fade-in zoom-in duration-300">
             <div className="mb-6 flex justify-center">
               <div className="p-3 bg-indigo-50 rounded-full">
                 <svg className="w-10 h-10 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
                 </svg>
               </div>
             </div>
             <h2 className="text-xl font-bold text-slate-900 mb-2">Setup API Key</h2>
             <p className="text-slate-600 mb-6 text-sm">
               Enter your Gemini API Key to start. It works on Android, Windows & Mac.
             </p>

             <div className="max-w-sm mx-auto space-y-3">
                <input 
                  type="password" 
                  placeholder="Paste Key (AIza...)"
                  value={manualKey}
                  onChange={(e) => setManualKey(e.target.value)}
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                />
                <button
                  onClick={handleSaveKey}
                  className="w-full px-6 py-3 rounded-lg bg-indigo-600 hover:bg-indigo-700 text-white font-medium shadow-md active:scale-95 transition-all"
                >
                  Start App
                </button>
                {window.aistudio && (
                  <button
                    onClick={handleConnectKey}
                    className="w-full px-6 py-3 rounded-lg border border-slate-300 text-slate-700 bg-white hover:bg-slate-50 font-medium mt-2"
                  >
                    Select Key (Google)
                  </button>
                )}
             </div>
           </div>
        )}

        {apiKeyReady && (
          <div className="bg-white rounded-2xl shadow-lg p-6 sm:p-8 border border-slate-200 animate-in fade-in slide-in-from-bottom-2 duration-500 relative">

            <button 
              onClick={handleClearKey}
              className="absolute top-4 right-4 text-slate-400 hover:text-red-500 p-2"
              title="Change API Key"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            </button>

            {/* File Input */}
            <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-300 rounded-xl p-8 bg-slate-50 hover:bg-indigo-50/30 transition-colors cursor-pointer relative group">
              <input
                type="file"
                accept="audio/*,video/*"
                onChange={handleFileChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              />
              <div className="transition-transform group-hover:scale-105 duration-200">
                 <svg className="w-12 h-12 text-blue-500 mb-3 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                 </svg>
              </div>
              <p className="text-slate-900 font-semibold text-center truncate w-full px-4">
                {state.file ? state.file.name : "Tap to select MP3 / MP4"}
              </p>
              {!state.file && <p className="text-xs text-slate-500 mt-1">Max 5GB</p>}
            </div>

            {state.error && (
              <div className="mt-4 p-3 bg-red-50 border border-red-100 text-red-600 rounded-lg text-sm flex items-start">
                 <svg className="w-5 h-5 mr-2 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                 {state.error}
              </div>
            )}

            {state.processing && (
               <div className="mt-6">
                  <div className="flex justify-between text-xs font-bold text-slate-500 mb-1 uppercase tracking-wide">
                    <span>{state.stage === 'uploading' ? 'Uploading...' : 'Transcribing...'}</span>
                    <span>{Math.round(state.uploadProgress || 0)}%</span>
                  </div>
                  <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                    <div 
                      className="bg-blue-600 h-2 rounded-full transition-all duration-300" 
                      style={{ width: `${state.uploadProgress}%` }}
                    ></div>
                  </div>
               </div>
            )}

            <button
              onClick={startTranscription}
              disabled={!state.file || state.processing}
              className={`mt-6 w-full py-3.5 px-6 rounded-xl font-bold text-white transition-all shadow-md flex items-center justify-center space-x-2 ${
                !state.file || state.processing
                  ? 'bg-slate-300 cursor-not-allowed text-slate-500'
                  : 'bg-blue-600 hover:bg-blue-700 active:scale-95'
              }`}
            >
              {state.processing ? (
                <>
                  <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  Processing...
                </>
              ) : (
                'Convert Now'
              )}
            </button>
          </div>
        )}

        {state.result && (
          <div className="bg-white rounded-2xl shadow-lg overflow-hidden border border-slate-200 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Tabs */}
            <div className="flex border-b border-slate-100">
              <button
                onClick={() => setActiveTab('transcription')}
                className={`flex-1 py-4 text-sm font-semibold text-center transition-colors ${activeTab === 'transcription' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                Transcription
              </button>
              <button
                onClick={() => setActiveTab('summary')}
                className={`flex-1 py-4 text-sm font-semibold text-center transition-colors ${activeTab === 'summary' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                Summary
              </button>
            </div>

            <div className="p-0">
               {activeTab === 'transcription' && (
                 <div className="p-6">
                   <div className="flex justify-between items-center mb-4">
                      <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Detected Language: {state.result.language}</span>
                      <button onClick={downloadText} className="text-blue-600 text-sm font-medium hover:underline flex items-center">
                        <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        Download
                      </button>
                   </div>
                   <div className="prose prose-slate prose-sm max-w-none whitespace-pre-wrap text-slate-800 leading-relaxed max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                     {state.result.transcription}
                   </div>
                 </div>
               )}

               {activeTab === 'summary' && (
                 <div className="p-6 bg-yellow-50/30 h-full min-h-[200px]">
                   <h3 className="text-sm font-bold text-slate-900 mb-3 uppercase tracking-wide flex items-center">
                     <svg className="w-4 h-4 mr-2 text-yellow-500" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1h4v1a2 2 0 11-4 0zM12 14c.015-.34.208-.646.477-.859a4 4 0 10-4.954 0c.27.213.462.519.476.859h4.002z" /></svg>
                     AI Summary
                   </h3>
                   <p className="text-slate-700 leading-relaxed text-base">
                     {state.result.summary}
                   </p>
                 </div>
               )}
            </div>
          </div>
        )}

      </main>

      <footer className="mt-12 text-slate-400 text-xs font-medium text-center">
        <p>Gemini Converter PWA</p>
      </footer>
    </div>
  );
};

export default App;

